        [Fact]
        public void DefaultCtor_ReturnsQuantityWithZeroValueAndBaseUnit()
        {
            var quantity = new NominalPower();
            Assert.Equal(0, quantity.Value);
            Assert.Equal(NominalPowerUnit.WattPeak, quantity.Unit);
        }

        [Fact]
        public void Ctor_WithInfinityValue_DoNotThrowsArgumentException()
        {
            var exception1 = Record.Exception(() => new NominalPower(double.PositiveInfinity, NominalPowerUnit.WattPeak));
            var exception2 = Record.Exception(() => new NominalPower(double.NegativeInfinity, NominalPowerUnit.WattPeak));

            Assert.Null(exception1);
            Assert.Null(exception2);
        }

        [Fact]
        public void Ctor_WithNaNValue_DoNotThrowsArgumentException()
        {
            var exception = Record.Exception(() => new NominalPower(double.NaN, NominalPowerUnit.WattPeak));

            Assert.Null(exception);
        }

        [Fact]
        public void NominalPower_QuantityInfo_ReturnsQuantityInfoDescribingQuantity()
        {
            NominalPowerUnit[] unitsOrderedByName = EnumHelper.GetValues<NominalPowerUnit>().OrderBy(x => x.ToString(), StringComparer.OrdinalIgnoreCase).ToArray();
            var quantity = new NominalPower(1, NominalPowerUnit.WattPeak);

            QuantityInfo<NominalPower, NominalPowerUnit> quantityInfo = quantity.QuantityInfo;

            Assert.Equal("NominalPower", quantityInfo.Name);
            Assert.Equal(NominalPower.Zero, quantityInfo.Zero);
            Assert.Equal(NominalPower.BaseUnit, quantityInfo.BaseUnitInfo.Value);
            Assert.Equal(unitsOrderedByName, quantityInfo.Units);
            Assert.Equal(unitsOrderedByName, quantityInfo.UnitInfos.Select(x => x.Value));
            Assert.Equal(NominalPower.Info, quantityInfo);
            Assert.Equal(quantityInfo, ((IQuantity)quantity).QuantityInfo);
            Assert.Equal(quantityInfo, ((IQuantity<NominalPowerUnit>)quantity).QuantityInfo);
        }

