        [Fact]
        public void As_UnitSystem_ReturnsValueInDimensionlessUnit()
        {
            var quantity = new NominalPower(value: 1, unit: NominalPowerUnit.WattPeak);

            var convertedValue = quantity.As(UnitSystem.SI);

            Assert.Equal(quantity.Value, convertedValue);
        }

        [Fact]
        public void As_UnitSystem_ThrowsArgumentNullExceptionIfNull()
        {
            var quantity = new NominalPower(value: 1, unit: NominalPower.BaseUnit);
            UnitSystem nullUnitSystem = null!;
            Assert.Throws<ArgumentNullException>(() => quantity.As(nullUnitSystem));
        }

        [Fact]
        public void ToUnit_UnitSystem_ReturnsValueInDimensionlessUnit()
        {
            var quantity = new NominalPower(value: 1, unit: NominalPowerUnit.WattPeak);

            NominalPower convertedQuantity = quantity.ToUnit(UnitSystem.SI);

            Assert.Equal(NominalPowerUnit.WattPeak, convertedQuantity.Unit);
            Assert.Equal(quantity.Value, convertedQuantity.Value);
        }

        [Fact]
        public void ToUnit_UnitSystem_ThrowsArgumentNullExceptionIfNull()
        {
            UnitSystem nullUnitSystem = null!;
            Assert.Multiple(() =>
            {
                var quantity = new NominalPower(value: 1, unit: NominalPower.BaseUnit);
                Assert.Throws<ArgumentNullException>(() => quantity.ToUnit(nullUnitSystem));
            }, () =>
            {
                IQuantity<NominalPowerUnit> quantity = new NominalPower(value: 1, unit: NominalPower.BaseUnit);
                Assert.Throws<ArgumentNullException>(() => quantity.ToUnit(nullUnitSystem));
            }, () =>
            {
                IQuantity quantity = new NominalPower(value: 1, unit: NominalPower.BaseUnit);
                Assert.Throws<ArgumentNullException>(() => quantity.ToUnit(nullUnitSystem));
            });
        }

