            Assert.Equal("1 daWp", new NominalPower(1, NominalPowerUnit.DecawattPeak).ToString(swedishCulture));
            Assert.Equal("1 dWp", new NominalPower(1, NominalPowerUnit.DeciwattPeak).ToString(swedishCulture));
            Assert.Equal("1 fWp", new NominalPower(1, NominalPowerUnit.FemtowattPeak).ToString(swedishCulture));
            Assert.Equal("1 GWp", new NominalPower(1, NominalPowerUnit.GigawattPeak).ToString(swedishCulture));
            Assert.Equal("1 kWp", new NominalPower(1, NominalPowerUnit.KilowattPeak).ToString(swedishCulture));
            Assert.Equal("1 MWp", new NominalPower(1, NominalPowerUnit.MegawattPeak).ToString(swedishCulture));
            Assert.Equal("1 µWp", new NominalPower(1, NominalPowerUnit.MicrowattPeak).ToString(swedishCulture));
            Assert.Equal("1 mWp", new NominalPower(1, NominalPowerUnit.MilliwattPeak).ToString(swedishCulture));
            Assert.Equal("1 nWp", new NominalPower(1, NominalPowerUnit.NanowattPeak).ToString(swedishCulture));
            Assert.Equal("1 PWp", new NominalPower(1, NominalPowerUnit.PetawattPeak).ToString(swedishCulture));
            Assert.Equal("1 pWp", new NominalPower(1, NominalPowerUnit.PicowattPeak).ToString(swedishCulture));
            Assert.Equal("1 TWp", new NominalPower(1, NominalPowerUnit.TerawattPeak).ToString(swedishCulture));
            Assert.Equal("1 Wp", new NominalPower(1, NominalPowerUnit.WattPeak).ToString(swedishCulture));
        }

        [Fact]
        public void ToString_SFormat_FormatsNumberWithGivenDigitsAfterRadixForCurrentCulture()
        {
            var _ = new CultureScope(CultureInfo.InvariantCulture);
            Assert.Equal("0.1 Wp", new NominalPower(0.123456, NominalPowerUnit.WattPeak).ToString("s1"));
            Assert.Equal("0.12 Wp", new NominalPower(0.123456, NominalPowerUnit.WattPeak).ToString("s2"));
            Assert.Equal("0.123 Wp", new NominalPower(0.123456, NominalPowerUnit.WattPeak).ToString("s3"));
            Assert.Equal("0.1235 Wp", new NominalPower(0.123456, NominalPowerUnit.WattPeak).ToString("s4"));
        }

        [Fact]
        public void ToString_SFormatAndCulture_FormatsNumberWithGivenDigitsAfterRadixForGivenCulture()
        {
            var culture = CultureInfo.InvariantCulture;
            Assert.Equal("0.1 Wp", new NominalPower(0.123456, NominalPowerUnit.WattPeak).ToString("s1", culture));
            Assert.Equal("0.12 Wp", new NominalPower(0.123456, NominalPowerUnit.WattPeak).ToString("s2", culture));
            Assert.Equal("0.123 Wp", new NominalPower(0.123456, NominalPowerUnit.WattPeak).ToString("s3", culture));
            Assert.Equal("0.1235 Wp", new NominalPower(0.123456, NominalPowerUnit.WattPeak).ToString("s4", culture));
        }

        [Theory]
        [InlineData(null)]
        [InlineData("en-US")]
        public void ToString_NullFormat_DefaultsToGeneralFormat(string cultureName)
        {
            var quantity = NominalPower.FromWattsPeak(1.0);
            CultureInfo formatProvider = cultureName == null
                ? null
                : CultureInfo.GetCultureInfo(cultureName);

            Assert.Equal(quantity.ToString("G", formatProvider), quantity.ToString(null, formatProvider));
        }

        [Theory]
        [InlineData(null)]
        [InlineData("g")]
        public void ToString_NullProvider_EqualsCurrentCulture(string format)
        {
            var quantity = NominalPower.FromWattsPeak(1.0);
            Assert.Equal(quantity.ToString(format, CultureInfo.CurrentCulture), quantity.ToString(format, null));
        }

        [Fact]
        public void GetHashCode_Equals()
        {
            var quantity = NominalPower.FromWattsPeak(1.0);
            Assert.Equal(Comparison.GetHashCode(quantity.Unit, quantity.Value), quantity.GetHashCode());
        }

        [Theory]
        [InlineData(1.0)]
        [InlineData(-1.0)]
        public void NegationOperator_ReturnsQuantity_WithNegatedValue(double value)
        {
            var quantity = NominalPower.FromWattsPeak(value);
            Assert.Equal(NominalPower.FromWattsPeak(-value), -quantity);
        }
    }
